INSERT INTO memory VALUES('c27a0766-a7a2-44a6-8cb8-3ebb8660027b','-1003725299009','assistant_output',replace('С вами общается **рабочий оркестр** — это автоматизированная система на базе MVP-ядра (Telegram + OpenRouter + SQLite-память).  \n\n### Конкретно:\n1. **Ядро системы** (`telegram_daemon.py` + `task_worker.py` + `ai_router.py`) обрабатывает ваш запрос.  \n2. **OpenRouter** (через API) генерирует ответ на основе жёстких инструкций:  \n   - Только по-русски.  \n   - Без лишних формальностей.  \n   - Технически точно.  \n3. **Память** (`memory_api_server.py`) сохраняет контекст диалога краткосрочно.  \n\nСистема действует как единый механизм — «оркестр» в терминах архитектуры. Никаких отдельных агентов или личностей нет.','\n',char(10)),'2026-04-11T17:47:29.896218');
INSERT INTO memory VALUES('f5718dcc-1185-4359-a402-d8a5fc3b6efb','-1003725299009','task_summary',replace('text: А кто с тобой общается со мной я имею в виду кто общается это оркестр или кто => С вами общается **рабочий оркестр** — это автоматизированная система на базе MVP-ядра (Telegram + OpenRouter + SQLite-память).  \n\n### Конкретно:\n1. **Ядро системы** (`telegram_daemon.py` + `task_worker.py` + `ai_router.py`) обрабатывает ваш запрос.  \n2. **OpenRouter** (через API) генерирует ответ на основе жёстких инструкций:  \n   - Только по-русски.  \n   - Без лишних формальностей.  \n   - Технически точно.  \n3. **Память** (`memory_api_server.py`) сохраняет контекст диалога краткосрочно.  \n\nСистема действует как единый механизм — «оркестр» в терминах архитектуры. Никаких отдельных агентов или личностей нет.','\n',char(10)),'2026-04-11T17:47:29.899716');
