INSERT INTO memory VALUES('e3ff87d5-3f60-417e-ab56-2505180d6bd8','-1003725299009','assistant_output',replace('Голосовой контур **не подключён**. Рабочее MVP-ядро обрабатывает **только текстовые запросы** через цепочку:  \n\n**Telegram → OpenRouter → SQLite-память**  \n\nДля активации голоса требуется:  \n1. Развёртывание STT (например, Whisper API)  \n2. Интеграция с `memory_api_server.py`  \n3. Тесты на задержки  \n\nСейчас система отвечает **строго по-русски** на текстовые команды. Если нужна техническая доработка — укажите чёткий ТЗ.  \n\n**Статус:**  \n- Текст: ✅  \n- Голос: ❌ (заглушка)  \n- Память: ✅ (краткосрочный контекст)  \n\nКоманда `/debug` покажет логи.','\n',char(10)),'2026-04-11T18:08:22.746813');
