INSERT INTO memory VALUES('f7739347-73cc-4ff3-9893-7d753e0d0b75','-1003725299009','assistant_output',replace('Голосовой контур **действительно не подключён**. Система понимает **только текст**, который вы вводите вручную.  \n\nЕсли вы отправляете голосовое сообщение:  \n1. Telegram автоматически конвертирует его в текст (если функция включена)  \n2. Бот получает уже **текстовую версию** вашего сообщения  \n3. Обрабатывает его через OpenRouter  \n\n**Техническая правка:**  \n- Ваш голос **не анализируется** системой напрямую  \n- Распознавание происходит на стороне Telegram (если включено)  \n\nДля полноценной голосовой интеграции нужно:  \n1. Развернуть STT (например, Whisper)  \n2. Настроить приём аудиофайлов в `telegram_daemon.py`  \n3. Добавить pipeline в `ai_router.py`  \n\nСейчас бот отвечает **только на текст**. Команда `/status` покажет текущие возможности.','\n',char(10)),'2026-04-11T18:09:05.295411');
