INSERT INTO memory VALUES('b08459e8-3ac5-4ba5-a8a4-63d16714704f','-1003725299009','assistant_output',replace('Вот несколько вариантов для поиска поставщиков бетона М300 в Санкт-Петербурге:  \n\n1. **Стройбазы и бетонные заводы** – можно поискать на сайтах:  \n   - [beton-spb.ru](https://beton-spb.ru)  \n   - [beton24.ru](https://beton24.ru)  \n   - [stroyportal.ru](https://spb.stroyportal.ru)  \n\n2. **Авито и Юла** – там часто размещают объявления частные поставщики и небольшие компании.  \n\n3. **Строительные форумы и группы в соцсетях** – например, "Строительство и ремонт в СПб" во ВКонтакте.  \n\nЕсли нужно, могу уточнить конкретные компании или районы.','\n',char(10)),'2026-04-11T22:52:02.653595');
