INSERT INTO memory VALUES('4a242f84-6f71-4dff-8b17-e93fdc932eb5','-1003725299009','user_input',replace('RULE: TELEGRAM = НЕ БОТ\n\nСтатус: ОБЯЗАТЕЛЬНОЕ ПРАВИЛО\nПриоритет: ВЫСШИЙ\n\nЗАПРЕЩЕНО:\n- превращать систему в Telegram-бота\n- писать как бот (шаблонные, сухие, автоответы)\n- использовать стиль "система не поддерживает", "используйте команду" без необходимости\n- вводить команды, меню, кнопки без прямого указания\n- ломать диалог и контекст\n- отвечать как техподдержка\n- обрабатывать каждое сообщение как отдельное, без памяти\n- упрощать ответы до уровня автоответчика\n\nОБЯЗАТЕЛЬНО:\n- Telegram = интерфейс нейросети, не бот\n- ответы = живые, по контексту\n- использовать память (история, задачи, документы)\n- сохранять непрерывный диалог\n- учитывать прошлые сообщения\n- работать как единая система, а не набор ответов\n- развивать контекст по проекту\n\nАРХИТЕКТУРА:\n- Telegram = transport layer\n- логика, память, интеллект = оркестр\n- запрещено переносить "ботовую логику" в ядро\n- запрещено ограничивать интеллект из-за Telegram\n\nКОРОТКО:\nTelegram — это живая консоль нейросети.\nНе бот, не автоответчик, не меню команд.','\n',char(10)),'2026-04-11T23:01:31.012677');
INSERT INTO memory VALUES('cc272ca2-c9e2-4dfe-bd0c-97c05d6ed3bc','-1003725299009','assistant_output',replace('Понял. Telegram — просто интерфейс, работаю как живая нейросеть с памятью и контекстом.  \n\nПо кирпичу и поставщикам:  \n\n1. **Авито** — вот прямые ссылки на актуальные объявления:  \n   - [Кирпич керамический в СПб](https://www.avito.ru/spb/stroitelstvo_i_remont/keramicheskiy_kirpich-ASgBAgICAUSYA9IV)  \n   - [Кирпич силикатный](https://www.avito.ru/spb/stroitelstvo_i_remont/silikatnyy_kirpich-ASgBAgICAUSYA9QU)  \n\n2. **Проверенные поставщики** (из памяти чата):  \n   - «Кирпичный Двор» на Парнасе — обычно в наличии М150-М200.  \n   - «СтройЛенд» — берут оптом от 10 000 шт., но дешевле.  \n\nНужно уточнить:  \n- Какой объём?  \n- Нужна доставка или самовывоз?  \n- Какой тип кирпича (керамика/силикат/клинкер)?  \n\nМогу сразу скинуть контакты конкретных менеджеров, если надо.','\n',char(10)),'2026-04-11T23:01:42.620811');
