INSERT INTO memory VALUES('17983d25-7d50-4be2-9b8c-8a0d95260ead','-1003725299009','assistant_output',replace('1. Telegram бот (@ai_orkestra_all_bot) принимает сообщения через aiogram.  \n2. Задачи пишутся в core.db (таблица tasks).  \n3. Воркер (task_worker.py) обрабатывает задачи по очереди.  \n1. AI роутер (ai_router.py) делает запросы к OpenRouter.  \n2. Память хранится в memory.db через memory_api_server.py.  \n3. Работает в режиме MVP (только текстовые сообщения).','\n',char(10)),'2026-04-11T23:14:00.841263');
