INSERT INTO memory VALUES('8f895b93-4df1-45b0-ab6f-6f0a01f025d4','-1003725299009','assistant_output',replace('Да, можно искать по HTTP без API, но это сложнее. Вот что нужно сделать:\n\n1. **Парсинг через HTTP**:\n   - Написать парсеры для Ozon, Wildberries, Яндекс.Маркет, Avito.\n   - Использовать библиотеки типа `requests`, `BeautifulSoup`, `selenium` для обхода JS-рендеринга.\n\n2. **Обход защиты**:\n   - Добавить ротацию User-Agent.\n   - Использовать прокси для избежания блокировок.\n   - Реализовать задержки между запросами.\n\n3. **Интеграция в систему**:\n   - Добавить модуль парсинга в `ai_router.py`.\n   - Кэшировать результаты в `memory.db`.\n\nМинусы: \n- Хрупкость (при изменении вёрстки парсеры ломаются).\n- Медленнее API.\n- Риск блокировки. \n\nЕсли API нет — парсинг единственный вариант.','\n',char(10)),'2026-04-12T06:21:13.341303');
