INSERT INTO memory VALUES('3d7242e7-6d23-4cc5-8c6a-2e8ce7f6581d','-1003725299009','assistant_output',replace('Если не хочешь подключать API, можно использовать веб-поиск через парсеры (например, BeautifulSoup, Selenium). Это дольше и менее стабильно, но не требует API-ключей.  \n\n**Что делать:**  \n1. В `ai_router.py` добавь вызов парсеров для Яндекс/Google (например, через `googlesearch-python`).  \n2. Для Ozon/Avito и других — парси через Selenium (если нет API).  \n3. Фильтруй результаты по ключевым словам из задачи.  \n\nМинусы:  \n- Медленнее API.  \n- Может ломаться при изменении вёрстки сайтов.  \n\nЕсли нужно быстрее — API обязательны. Выбирай: либо тратить время на парсеры, либо подключать API.','\n',char(10)),'2026-04-12T06:21:37.320137');
