INSERT INTO memory VALUES('8934914c-c28a-4dfa-b6b0-34beecfc90ce','-1003725299009','assistant_output',replace('Разработка парсеров вместо использования API — решение рабочее, но сложное. Вот ключевые моменты:\n\n1. **Технический стек для парсинга**:\n   - `requests` + `BeautifulSoup` — для статических сайтов\n   - `selenium`/`playwright` — для JS-рендеринга (Ozon, Wildberries)\n   - `scrapy` — для масштабирования\n\n2. **Обязательные механизмы защиты**:\n   - Ротация прокси (Luminati, Smartproxy)\n   - Кастомные User-Agent\n   - Рандомные задержки 3-10 сек\n   - Обход капчи (AntiCaptcha, 2Captcha)\n\n3. **Специфика по площадкам**:\n   - **Ozon**: Жёсткий антипарсинг, нужны residential прокси\n   - **Wildberries**: Динамические классы CSS, требуется регулярное обновление селекторов\n   - **Avito**: Блокирует по TLS-отпечаткам\n\n4. **Интеграция в текущую систему**:\n   - Добавить модуль `parsers/` с отдельными классами под каждую площадку\n   - В `ai_router.py` — роутинг запросов типа "найди на Ozon {query}"\n   - Кешировать результаты в `memory.db`\n\n5. **Юридические риски**:\n   - Проверять robots.txt\n   - Ограничивать частоту запросов\n   - Рассмотреть headless-браузеры через облака (Browserless)\n\nДля старта лучше начать с Avito (проще) + один маркетплейс. Готовые решения типа ParseHub или Apify могут сэкономить время, но будут дороже в долгосрочной перспективе.','\n',char(10)),'2026-04-12T06:22:29.862189');
