INSERT INTO memory VALUES('78daefac-7c40-4142-9b1c-6ddce35d0b37','-1003725299009','assistant_output','Каждый чат должен иметь чёткую специализацию и фокус на определённых задачах. Если пользователь отклоняется от темы, система должна напоминать о назначении чата и возвращать обсуждение в нужное русло. Исключение — интернет-поиск, который может быть выполнен из любого чата.','2026-04-12T06:37:25.383653');
INSERT INTO memory VALUES('ed0b90dc-f321-41d6-a9a6-dc395359bd57','-1003725299009','task_summary','text: Да и так должно быть по каждому чату => Каждый чат должен иметь чёткую специализацию и фокус на определённых задачах. Если пользователь отклоняется от темы, система должна напоминать о назначении чата и возвращать обсуждение в нужное русло. Исключение — интернет-поиск, который может быть выполнен из любого чата.','2026-04-12T06:37:25.387041');
INSERT INTO memory VALUES('33112ef2-53bb-4ea4-9235-43d3a9fc388a','-1003725299009','assistant_output',replace('Для реализации задачи:\n\n1. **Детект типа запроса**:\n   - В `need_web_search()` добавь проверку на ключевые слова:\n     ```python\n     def need_web_search(query):\n         commercial_keywords = ["купить", "цена", "стоимость", "сколько стоит", "объявление", "продажа", "в наличии", "заказать"]\n         return any(keyword in query.lower() for keyword in commercial_keywords)\n     ```\n\n2. **Marketplace Search**:\n   - В `web_search()` добавь список сайтов и логику для коммерческого поиска:\n     ```python\n     def web_search(query):\n         sites = [\n             "site:avito.ru",\n             "site:ozon.ru",\n             "site:wildberries.ru",\n             "site:auto.ru",\n             "site:drom.ru"\n         ]\n         if need_web_search(query):\n             results = []\n             for site in sites:\n                 search_query = f"{query} {site}"\n                 # Здесь выполни поиск и добавь результаты в список results\n                 # Пример: results.extend(search_function(search_query))\n             return results[:7]  # Ограничение на 7 результатов\n         else:\n             return ddgs_search(query)  # Обычный поиск\n     ```\n\n3. **Сбор результатов**:\n   - Убедись, что результаты уникальны по ссылкам:\n     ```python\n     def remove_duplicates(results):\n         seen = set()\n         unique_results = []\n         for result in results:\n             if result[''link''] not in seen:\n                 seen.add(result[''link''])\n                 unique_results.append(result)\n         return unique_results\n     ```\n\n4. **Формат выдачи**:\n   - Форматируй каждый результат:\n     ```python\n     def format_result(result):\n         return f"{result[''title'']} — {result[''description''][:200]}. Источник: {result[''link'']}"\n     ```\n\n5. **Обычный поиск**:\n   - Если запрос не коммерческий или результаты не найдены, выполни обычный поиск:\n     ```python\n     def ddgs_search(query):\n         # Здесь выполни обычный поиск через DDGS\n         pass\n     ```\n\n6. **Ограничение**:\n   - Ограничь итоговый результат:\n     ```python\n     def web_search(query):\n         results = perform_search(query)\n         return results[:1500]\n     ```\n\n7. **Запреты**:\n   - Убедись, что не возвращаешь HTML, не используешь `requests fallback`, не возвращаешь заглушки и не возвращаешь пустой текст, если есть результаты.\n\n**Проверка**:\n- Протестируй с запросами:\n  - `купить кирпич м150 москва`\n  - `цена бетона м300`\n  - `что такое бетон м300`\n  \nУбедись, что результаты соответствуют ожиданиям.','\n',char(10)),'2026-04-12T06:42:28.665391');
