INSERT INTO memory VALUES('eb2a93a4-0e8e-4126-85cf-bc9cc45f8061','-1003725299009','user_input',replace('Требуется устранить замечания\012 1. Импорт неправильный\012\012Было:\012\012from duckduckgo_search import ddgs\012\012Заменить на:\012\012from duckduckgo_search import DDGS\012\012 2. Коммерческий поиск переписать\012\012Было:\012\012def commercial_search(query):\012    sites = ["avito.ru", "ozon.ru", "wildberries.ru", "auto.ru", "drom.ru"]\012    results = []\012    for site in sites:\012        search_query = f"{query} site:{site}"\012        site_results = ddgs.text(search_query, max_results=2)\012        for res in site_results:\012            if res[''link''] not in [r[''link''] for r in results]:\012                results.append(res)\012        if len(results) >= 7:\012            break\012    return results\012\012Заменить на:\012\012def commercial_search(query):\012    sites = ["avito.ru", "ozon.ru", "wildberries.ru", "auto.ru", "drom.ru"]\012    results = []\012    seen = set()\012\012    with DDGS() as ddgs:\012        for site in sites:\012            search_query = f"{query} site:{site}"\012            site_results = list(ddgs.text(search_query, max_results=2))\012            for res in site_results:\012                href = res.get("href", "")\012                if href and href not in seen:\012                    seen.add(href)\012                    results.append(res)\012            if len(results) >= 7:\012                break\012\012    return results[:7]\012\012 3. Обычный поиск переписать\012\012Было:\012\012def info_search(query):\012    return ddgs.text(query, max_results=5)\012\012Заменить на:\012\012def info_search(query):\012    with DDGS() as ddgs:\012        return list(ddgs.text(query, max_results=5))\012\012 4. Поля результатов неправильные\012\012Не использовать:\012\012res[''link'']\012res.get(''description'', '''')\012\012Использовать:\012\012res.get("href", "")\012res.get("body", "")\012\012 5. Форматирование заменить полностью\012\012Было:\012\012def format_results(results):\012    formatted = []\012    for res in results:\012        title = res.get(''title'', '''')\012        description = res.get(''description'', '''')[:200]\012        link = res.get(''link'', '''')\012        formatted.append(f"{title} — {description}. Источник: {link}")\012    return "\n".join(formatted)\012\012Заменить на:\012\012def format_results(results):\012    formatted = []\012    for res in results:\012        title = res.get("title", "").strip()\012        body = res.get("body", "").strip()[:200]\012        href = res.get("href", "").strip()\012        if title and href:\012            formatted.append(f"{title} — {body}. Источник: {href}")\012    return "\n\n".join(formatted)\012\012 6. Основную функцию оставить в таком виде\012\012def web_search(query):\012    if need_web_search(query):\012        results = commercial_search(query)\012    else:\012        results = info_search(query)\012\012    formatted_results = format_results(results)\012    return formatted_results[:1500] if formatted_results else ""\012\012 7. Больше ничего не менять\012\012Выполнять строго по этим правкам и не трогать другие файлы','\012',char(10)),'2026-04-12T07:03:06.333238');
INSERT INTO memory VALUES('d14cd50d-0ee3-4077-a68b-3903fc5ca9aa','-1003725299009','assistant_output',replace('Принято. Вношу изменения в `ai_router.py`:\012\0121. Исправляю импорт:\012```python\012from duckduckgo_search import DDGS\012```\012\0122. Обновляю функцию `commercial_search`:\012```python\012def commercial_search(query):\012    sites = ["avito.ru", "ozon.ru", "wildberries.ru", "auto.ru", "drom.ru"]\012    results = []\012    seen = set()\012\012    with DDGS() as ddgs:\012        for site in sites:\012            search_query = f"{query} site:{site}"\012            site_results = list(ddgs.text(search_query, max_results=2))\012            for res in site_results:\012                href = res.get("href", "")\012                if href and href not in seen:\012                    seen.add(href)\012                    results.append(res)\012            if len(results) >= 7:\012                break\012\012    return results[:7]\012```\012\0123. Обновляю функцию `info_search`:\012```python\012def info_search(query):\012    with DDGS() as ddgs:\012        return list(ddgs.text(query, max_results=5))\012```\012\0124. Использую правильные поля результатов:\012```python\012res.get("href", "")\012res.get("body", "")\012```\012\0125. Обновляю форматирование:\012```python\012def format_results(results):\012    formatted = []\012    for res in results:\012        title = res.get("title", "").strip()\012        body = res.get("body", "").strip()[:200]\012        href = res.get("href", "").strip()\012        if title and href:\012            formatted.append(f"{title} — {body}. Источник: {href}")\012    return "\n\n".join(formatted)\012```\012\0126. Оставляю основную функцию без изменений:\012```python\012def web_search(query):\012    if need_web_search(query):\012        results = commercial_search(query)\012    else:\012        results = info_search(query)\012\012    formatted_results = format_results(results)\012    return formatted_results[:1500] if formatted_results else ""\012```\012\012Изменения внесены строго по указанным правкам.','\012',char(10)),'2026-04-12T07:03:23.514079');
