INSERT INTO memory VALUES('9ee5b173-dc51-42e0-a963-f467367e2fb1','-1003725299009','assistant_output',replace('Вот исправленный код для `web_engine.py`:\012\012```python\012from duckduckgo_search import DDGS\012\012def commercial_search(query):\012    sites = ["avito.ru", "ozon.ru", "wildberries.ru", "auto.ru", "drom.ru"]\012    results = []\012    seen = set()\012\012    with DDGS() as ddgs:\012        for site in sites:\012            search_query = f"{query} site:{site}"\012            site_results = list(ddgs.text(search_query, max_results=2))\012            for res in site_results:\012                if res.get(''href'', '''') not in seen:\012                    seen.add(res.get(''href'', ''''))\012                    results.append({\012                        ''title'': res.get(''title'', ''''),\012                        ''href'': res.get(''href'', ''''),\012                        ''body'': res.get(''body'', '''')\012                    })\012    return results\012\012def info_search(query):\012    results = []\012    with DDGS() as ddgs:\012        search_results = list(ddgs.text(query, max_results=5))\012        for res in search_results:\012            results.append({\012                ''title'': res.get(''title'', ''''),\012                ''href'': res.get(''href'', ''''),\012                ''body'': res.get(''body'', '''')\012            })\012    return results\012\012def format_results(results):\012    formatted = []\012    for res in results:\012        formatted.append(f"{res[''title'']}\n{res[''href'']}\n{res[''body'']}")\012    return "\n\n".join(formatted)\012\012def web_search(query, search_type="info"):\012    if search_type == "commercial":\012        results = commercial_search(query)\012    else:\012        results = info_search(query)\012    return format_results(results)\012```\012\012Изменения:\0121. Исправлен импорт на `from duckduckgo_search import DDGS`\0122. Все функции используют контекстный менеджер `with DDGS()`\0123. Добавлена