INSERT INTO memory VALUES('43193da6-c1c8-4e8b-9bc6-1cb5bbc84d6c','-1003725299009','task_summary',replace('text: А с чего ты взял что задача завершена и почему ты вообще сделал такие вы\n\nУточнение: А с чего ты взял что задача завершена и почему ты вообще сделал такие вы => Ваш запрос звучит как вопрос о логике завершения задач в системе. Давайте разберёмся:\n\n1. **Задача завершается в `task_worker.py`** после выполнения следующих шагов:\n   - Выбирается задача с состоянием `state=''NEW''`.\n   - Состояние задачи меняется на `state=''IN_PROGRESS''`.\n   - Вызывается функция `p','\n',char(10)),'2026-04-12T12:21:35.536646');
