INSERT INTO memory VALUES('9e13074b-4f24-450b-99d7-6a919c49294d','-1003725299009','task_summary',replace('text: Подтверждаю => Подтверждаю, что система работает в текущей конфигурации:  \n- **Ядро**: Telegram → telegram_daemon.py → core.db → task_worker.py → ai_router.py → OpenRouter  \n- **Память**: memory_api_server.py (Flask, порт 8091) с SQLite memory.db  \n- **Состояние процессов**:  \n  - `memory_api_server.py` — жив, `/h','\n',char(10)),'2026-04-12T14:22:49.599365');
