INSERT INTO memory VALUES('72f55b24-7c08-4151-9055-aeac1584504b','-1003725299009','task_summary',replace('text: Да уточняю как твои дела что ты все от отваливается ся на хуй тут мудаки эти заебали меня уже тебя чинить => Текущее состояние системы:  \n- Ядро работает (Telegram → OpenRouter → Telegram)  \n- Память доступна через memory_api_server.py  \n- Обработка текста активна, голосовые сообщения не поддерживаются  \n\nОшибки в логах:  \n- Ранее были проблемы с переходами состояний задач (NEW → IN_PROGRESS)  \n- Фиксы уже','\n',char(10)),'2026-04-12T22:14:21.390773');
