INSERT INTO memory VALUES('d24b59c1-d573-47f5-a709-d5eb5dfc4ffe','-1003725299009','assistant_output',replace('Отбой задач в системе AREAL-NEVA CORE выполняется через очистку таблицы tasks в core.db. Для этого:\n\n1. Остановите task_worker.py и telegram_daemon.py\n2. Выполните SQL-запрос:\n```sql\nDELETE FROM tasks WHERE state IN (''NEW'', ''IN_PROGRESS'');\n```\n3. Перезапустите процессы\n\nДля отбоя только конкретных типов задач добавьте условие WHERE по полям input_type или chat_id.','\n',char(10)),'2026-04-12T23:40:55.804027');
